before_code:
module synchronous_counter(
  input clk,
  input rst_n,
  output reg [15:0] count
);

  always @(posedge clk)
  begin
    if (~rst_n)
      count <= 16'h0000;
    else
      count <= count + 1;
  end

endmodule

after_code:
module synchronous_counter(
  input clk,
  input rst_n,
  output reg [15:0] count
);

  always @(posedge clk or negedge rst_n)
  begin
    if (~rst_n)
      count <= 16'h0000;
    else
      count <= count + 1;
  end

endmodule
